SELECT ${1:*}
FROM ${2:table_name}
WHERE ${3:condition};

SELECT ${1:t1.*}, ${2:t2.column}
FROM ${3:table1} ${4:t1}
INNER JOIN ${5:table2} ${6:t2} ON ${4:t1}.${7:id} = ${6:t2}.${8:foreign_key};

SELECT ${1:t1.*}, ${2:t2.column}
FROM ${3:table1} ${4:t1}
LEFT JOIN ${5:table2} ${6:t2} ON ${4:t1}.${7:id} = ${6:t2}.${8:foreign_key};

SELECT ${1:column}, COUNT(*) as ${2:count}
FROM ${3:table_name}
GROUP BY ${1:column};

SELECT ${1:column}, COUNT(*) as ${2:count}
FROM ${3:table_name}
GROUP BY ${1:column}
HAVING COUNT(*) > ${4:threshold};

SELECT ${1:*}
FROM ${2:table_name}
ORDER BY ${3:column} ${4:ASC};

SELECT ${1:*}
FROM ${2:table_name}
LIMIT ${3:10} OFFSET ${4:0};

UPDATE ${1:table_name}
SET ${2:column1} = ${3:value1}
WHERE ${4:condition};

UPDATE ${1:table_name}
SET ${2:column1} = ${3:value1},
    ${4:column2} = ${5:value2}
WHERE ${6:condition};

CREATE TABLE ${1:table_name} (
	${2:id} INT PRIMARY KEY AUTO_INCREMENT,
	${3:column1} ${4:VARCHAR(255)} NOT NULL,
	${5:column2} ${6:TEXT},
	${7:created_at} TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE ${1:table_name} (
	${2:id} INT PRIMARY KEY AUTO_INCREMENT,
	${3:user_id} INT NOT NULL,
	${4:column1} ${5:VARCHAR(255)},
	FOREIGN KEY (${3:user_id}) REFERENCES ${6:users}(${7:id})
);

CREATE VIEW ${1:view_name} AS
SELECT ${2:columns}
FROM ${3:table_name}
WHERE ${4:condition};

SELECT ${1:*}
FROM ${2:table1}
WHERE ${3:column} IN (
	SELECT ${4:column}
	FROM ${5:table2}
	WHERE ${6:condition}
);

CASE
	WHEN ${1:condition1} THEN ${2:result1}
	WHEN ${3:condition2} THEN ${4:result2}
	ELSE ${5:default_result}
END

CASE ${1:column}
	WHEN ${2:value1} THEN ${3:result1}
	WHEN ${4:value2} THEN ${5:result2}
	ELSE ${6:default_result}
END

BEGIN TRANSACTION;

${1:-- SQL statements}

COMMIT;

BEGIN TRANSACTION;

${1:-- SQL statements}

-- If error occurs:
-- ROLLBACK;
-- Otherwise:
COMMIT;

SELECT ${1:columns}
FROM ${2:table1}
WHERE ${3:condition1}

UNION

SELECT ${1:columns}
FROM ${4:table2}
WHERE ${5:condition2};

WITH ${1:cte_name} AS (
	SELECT ${2:columns}
	FROM ${3:table_name}
	WHERE ${4:condition}
)
SELECT ${5:*}
FROM ${1:cte_name};

SELECT ${1:*},
	ROW_NUMBER() OVER (
		PARTITION BY ${2:partition_column}
		ORDER BY ${3:order_column}
	) AS ${4:row_num}
FROM ${5:table_name};

SELECT ${1:*},
	RANK() OVER (
		PARTITION BY ${2:partition_column}
		ORDER BY ${3:order_column} DESC
	) AS ${4:rank}
FROM ${5:table_name};

SELECT ${1:*},
	SUM(${2:amount}) OVER (
		PARTITION BY ${3:partition_column}
		ORDER BY ${4:order_column}
		ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
	) AS ${5:running_total}
FROM ${6:table_name};

SELECT ${1:*},
	LAG(${2:column}) OVER (ORDER BY ${3:order_column}) AS ${4:prev_value},
	LEAD(${2:column}) OVER (ORDER BY ${3:order_column}) AS ${5:next_value}
FROM ${6:table_name};

SELECT ${1:*},
	AVG(${2:column}) OVER (
		ORDER BY ${3:order_column}
		ROWS BETWEEN ${4:2} PRECEDING AND CURRENT ROW
	) AS ${5:moving_avg}
FROM ${6:table_name};

WITH RECURSIVE ${1:cte_name} AS (
	-- Base case
	SELECT ${2:id}, ${3:parent_id}, ${4:name}, 1 AS ${5:level}
	FROM ${6:table_name}
	WHERE ${3:parent_id} IS NULL

	UNION ALL

	-- Recursive case
	SELECT t.${2:id}, t.${3:parent_id}, t.${4:name}, c.${5:level} + 1
	FROM ${6:table_name} t
	JOIN ${1:cte_name} c ON t.${3:parent_id} = c.${2:id}
)
SELECT * FROM ${1:cte_name};

WITH
${1:cte1} AS (
	SELECT ${2:columns}
	FROM ${3:table1}
	WHERE ${4:condition1}
),
${5:cte2} AS (
	SELECT ${6:columns}
	FROM ${7:table2}
	WHERE ${8:condition2}
)
SELECT ${9:*}
FROM ${1:cte1}
JOIN ${5:cte2} ON ${10:join_condition};

SELECT ${1:columns}
FROM ${2:table_name}
WHERE ${3:condition}
GROUP BY ${4:group_column}
HAVING ${5:aggregate_condition}
ORDER BY ${6:sort_column} ${7:DESC}
LIMIT ${8:10};

SELECT ${1:*}
FROM ${2:table1} ${3:t1}
WHERE EXISTS (
	SELECT 1
	FROM ${4:table2} ${5:t2}
	WHERE ${5:t2}.${6:foreign_key} = ${3:t1}.${7:id}
);

SELECT ${1:t1.*},
	(SELECT ${2:COUNT(*)}
	 FROM ${3:table2} ${4:t2}
	 WHERE ${4:t2}.${5:foreign_key} = ${6:t1}.${7:id}
	) AS ${8:sub_count}
FROM ${9:table1} ${6:t1};

SELECT ${1:t1.*}, ${2:t2.column}, ${3:t3.column}
FROM ${4:table1} ${5:t1}
INNER JOIN ${6:table2} ${7:t2} ON ${5:t1}.${8:id} = ${7:t2}.${9:foreign_key}
LEFT JOIN ${10:table3} ${11:t3} ON ${7:t2}.${12:id} = ${11:t3}.${13:foreign_key}
WHERE ${14:condition};

SELECT ${1:a.column}, ${2:b.column}
FROM ${3:table_name} ${4:a}
INNER JOIN ${3:table_name} ${5:b} ON ${4:a}.${6:parent_id} = ${5:b}.${7:id};

INSERT INTO ${1:target_table} (${2:column1}, ${3:column2})
SELECT ${4:col1}, ${5:col2}
FROM ${6:source_table}
WHERE ${7:condition};

MERGE INTO ${1:target_table} ${2:t}
USING ${3:source_table} ${4:s}
ON ${2:t}.${5:id} = ${4:s}.${5:id}
WHEN MATCHED THEN
	UPDATE SET ${6:column1} = ${4:s}.${6:column1}
WHEN NOT MATCHED THEN
	INSERT (${5:id}, ${6:column1})
	VALUES (${4:s}.${5:id}, ${4:s}.${6:column1});

CREATE TEMPORARY TABLE ${1:temp_table} AS
SELECT ${2:columns}
FROM ${3:source_table}
WHERE ${4:condition};

ALTER TABLE ${1:table_name}
ADD CONSTRAINT ${2:constraint_name}
${3:FOREIGN KEY} (${4:column}) ${5:REFERENCES other_table(id)};

CREATE INDEX ${1:idx_name}
ON ${2:table_name}(${3:column})
WHERE ${4:condition};

CREATE MATERIALIZED VIEW ${1:view_name} AS
SELECT ${2:columns}
FROM ${3:table_name}
WHERE ${4:condition};

-- REFRESH MATERIALIZED VIEW ${1:view_name};

CREATE OR REPLACE FUNCTION ${1:function_name}(${2:param1 INT})
RETURNS ${3:VOID} AS $$
BEGIN
	${4:-- function body}
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE PROCEDURE ${1:procedure_name}(${2:param1 INT})
LANGUAGE plpgsql AS $$
BEGIN
	${3:-- procedure body}
END;
$$;

CREATE TRIGGER ${1:trigger_name}
${2:BEFORE} ${3:INSERT OR UPDATE} ON ${4:table_name}
FOR EACH ROW
EXECUTE FUNCTION ${5:trigger_function}();

SELECT ${1:*}
FROM ${2:table_name}
ORDER BY ${3:id}
OFFSET ${4:0} ROWS
FETCH NEXT ${5:10} ROWS ONLY;

SELECT DISTINCT ON (${1:group_column})
	${2:*}
FROM ${3:table_name}
ORDER BY ${1:group_column}, ${4:order_column} DESC;

SELECT ${1:group_column},
	SUM(CASE WHEN ${2:pivot_column} = '${3:value1}' THEN ${4:measure} ELSE 0 END) AS ${3:value1},
	SUM(CASE WHEN ${2:pivot_column} = '${5:value2}' THEN ${4:measure} ELSE 0 END) AS ${5:value2}
FROM ${6:table_name}
GROUP BY ${1:group_column};

SELECT ${1:group_column},
	STRING_AGG(${2:column}, '${3:, }' ORDER BY ${4:column})
FROM ${5:table_name}
GROUP BY ${1:group_column};

SELECT ${1:*}
FROM ${2:table_name}
WHERE ${3:created_at} >= '${4:2024-01-01}'
	AND ${3:created_at} < '${5:2024-02-01}';

BEGIN;

${1:-- first operation}

SAVEPOINT ${2:sp1};

${3:-- second operation (can be rolled back independently)}

-- ROLLBACK TO ${2:sp1};  -- undo second operation only

COMMIT;

INSERT INTO ${1:table_name} (${2:column1}, ${3:column2})
VALUES (${4:value1}, ${5:value2})
RETURNING ${6:*};

UPDATE ${1:table_name}
SET ${2:column} = ${3:value}
WHERE ${4:condition}
RETURNING ${5:*};

DELETE FROM ${1:table_name}
WHERE ${2:condition}
RETURNING ${3:*};
